        <div class="flex items-center justify-center w-full transition-opacity opacity-100 duration-750 lg:grow">
            <main class="flex max-w-[335px] w-full flex-col-reverse lg:max-w-4xl lg:flex-row">
                <div class="text-[13px] leading-[20px] flex-1 p-6 pb-12 lg:p-20 bg-white shadow-[inset_0px_0px_0px_1px_rgba(26,26,0,0.16)] rounded-bl-lg rounded-br-lg lg:rounded-tl-lg lg:rounded-br-none">
                    <h1 class="mb-1 font-medium text-[20px]">Sistem Informasi Pengarsip</h1>
                    <p class="mb-2 text-[#706f6c]">Puskesmas Pantai Amal - Solusi digital untuk manajemen arsip yang efisien dan terintegrasi.</p>
                    
                    <ul class="flex flex-col mb-4 lg:mb-6">
                        <li class="flex items-center gap-4 py-2 relative before:border-l before:border-[#e3e3e0] before:top-1/2 before:bottom-0 before:left-[0.4rem] before:absolute">
                            <span class="relative py-1 bg-white">
                                <span class="flex items-center justify-center rounded-full bg-[#FDFDFC] shadow-[0px_0px_1px_0px_rgba(0,0,0,0.03),0px_1px_2px_0px_rgba(0,0,0,0.06)] w-3.5 h-3.5 border border-[#e3e3e0]">
                                    <span class="rounded-full bg-[#dbdbd7] w-1.5 h-1.5"></span>
                                </span>
                            </span>
                            <span>
                                Arsip Digital Terintegrasi
                                <a href="#features" class="inline-flex items-center space-x-1 font-medium underline underline-offset-4 text-[#0EA5E9] ml-1">
                                    <span>Selengkapnya</span>
                                    <svg width="10" height="11" viewBox="0 0 10 11" fill="none" xmlns="http://www.w3.org/2000/svg" class="w-2.5 h-2.5">
                                        <path d="M7.70833 6.95834V2.79167H3.54167M2.5 8L7.5 3.00001" stroke="currentColor" stroke-linecap="square"/>
                                    </svg>
                                </a>
                            </span>
                        </li>
                        
                        <li class="flex items-center gap-4 py-2 relative before:border-l before:border-[#e3e3e0] before:bottom-1/2 before:top-0 before:left-[0.4rem] before:absolute">
                            <span class="relative py-1 bg-white">
                                <span class="flex items-center justify-center rounded-full bg-[#FDFDFC] shadow-[0px_0px_1px_0px_rgba(0,0,0,0.03),0px_1px_2px_0px_rgba(0,0,0,0.06)] w-3.5 h-3.5 border border-[#e3e3e0]">
                                    <span class="rounded-full bg-[#dbdbd7] w-1.5 h-1.5"></span>
                                </span>
                            </span>
                            <span>
                                Manajemen Dokumen Efisien
                                <a href="#about" class="inline-flex items-center space-x-1 font-medium underline underline-offset-4 text-[#0EA5E9] ml-1">
                                    <span>Pelajari Lebih Lanjut</span>
                                    <svg width="10" height="11" viewBox="0 0 10 11" fill="none" xmlns="http://www.w3.org/2000/svg" class="w-2.5 h-2.5">
                                        <path d="M7.70833 6.95834V2.79167H3.54167M2.5 8L7.5 3.00001" stroke="currentColor" stroke-linecap="square"/>
                                    </svg>
                                </a>
                            </span>
                        </li>
                    </ul>
                    
                    <ul class="flex gap-3 text-sm leading-normal">
                        <li>
                            <a href="#start" class="inline-block hover:bg-[#0EA5E9] px-5 py-1.5 bg-[#0EA5E9] rounded-sm border border-[#0EA5E9] text-white text-sm leading-normal transition-all">
                                Mulai Sekarang
                            </a>
                        </li>
                    </ul>
                </div>
            </main>
        </div>

        <div class="h-14.5 hidden lg:block"></div>
